import requests
from urllib.parse import urlparse

ALLOWLISTED_HOSTS = {"example.com", "api.partner.com"}  # Add allowed hosts here

def is_valid_url(url):
    parsed_url = urlparse(url)
    if parsed_url.scheme not in {"http", "https"}:
        return False
    if parsed_url.hostname not in ALLOWLISTED_HOSTS:
        return False
    if parsed_url.hostname in {"localhost", "127.0.0.1"} or \
       parsed_url.hostname.startswith("169.254.") or \
       parsed_url.hostname.startswith("10.") or \
       parsed_url.hostname.startswith("172.") or \
       parsed_url.hostname.startswith("192.168."):
        return False
    return True

def fetch_url_content(url):
    if not is_valid_url(url):
        raise ValueError("Invalid URL or destination not allowed.")
    
    try:
        response = requests.get(url, allow_redirects=False)
        response.raise_for_status()
        return response.text
    except requests.exceptions.RequestException as e:
        raise RuntimeError(f"Error fetching URL: {e}")

